var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"부대 신설에 대한 제 이야기는 여기까지입니다. 장관님의 견해를 듣고 싶군요.","JPN":"部隊新設についての私の話はここまでです。長官のご意見をお聞かせください。","ENG":"That concludes my brief on the establishment of the new unit. I'd appreciate your insight on the matter, Mr. Secretary.","TWN":"關於新創部隊的事就是這些了，我想聽聽長官您的意見。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"......그러니까 요약하면 대 침식전 전문의 새로운 부대를 창설하자는 이야기로군.","JPN":"……要するに、対侵食戦専門の新しい部隊を創設するって話だな。","ENG":"So basically you want to create a new unit specializing in anti-Corruption warfare.","TWN":"……簡單來講，就是建設一個新部隊專門進行侵蝕戰嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇습니다.","JPN":"そうです｡","ENG":"That's right.","TWN":"是的。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"하지만 굳이 새로운 부대를 만들 필요가 있을까?","JPN":"だが、わざわざ新しい部隊を作る必要があるのか？","ENG":"But do we really need to create a whole new unit for that?","TWN":"不過有必要成立一個新的部隊嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"애초에 자네는 태스크포스 1 엔터프라이즈의 사령관이지 않나?","JPN":"そもそも君はタスクフォース1エンタープライズの司令官じゃないか？","ENG":"You're the commanding general of the TASKFORCE 1 Enterprise in the first place.","TWN":"妳從一開始就是第一特遣勢力企業的司令官不是嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"새로운 부대를 만들고 나면 예전 부대는 버릴 생각인가?","JPN":"新しい部隊を作るとなると、あの部隊は見捨てる気か？","ENG":"Are you going to abandon your current post once you create this new unit?","TWN":"成立新的部隊後，原來的部隊怎麼辦？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......잘 아시면서 그런 말씀을 하시는군요.","JPN":"……よくご存知なのに、そんなことをおっしゃるのですね。","ENG":"I'm sure you know better than that.","TWN":"……您真是明知故問啊。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"기함인 엔터프라이즈는 파손과 노후화가 심해서 도크에 들어간 지 오래고, 저와 도미닉을 제외한 주요 멤버들도 대부분 전역하거나 실종된 상황입니다.","JPN":"旗艦であるエンタープライズは破損や老朽化が激しく、ずっとドックに入ったままですし、私とドミニークを除いたメインメンバーのほとんどが、除隊したり失踪している状態です。","ENG":"The flagship Enterprise has been sitting on the dock for a while now due to serious damages and obsolescence. Most key members aside from Dominic and I have already retired or gone M.I.A.","TWN":"企業號艦船由於嚴重的損壞與老化，很早就進了船塢，而除了我和多明尼克之外，大部分成員不是失蹤就是退伍。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"사실상 부대 해산 상황이라고 해도 크게 다르지 않겠죠.","JPN":"事実上、部隊解散と言っても過言ではありません。","ENG":"The unit has virtually been disbanded, really.","TWN":"事實上，就算解散部隊也不會有什麼差別。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그렇다고 해서 새로운 부대를 만들겠다는 건 너무 앞서간 이야기 같은데.","JPN":"そうだとしても、新しい部隊を作るって話は早すぎると思うが。","ENG":"Even so, creating a new unit sounds like a stretch.","TWN":"話雖如此，成立一個新的部隊好像有點太早了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"태스크포스 1을 재정비하는 것이 재정적으로도 이득이지 않나?","JPN":"タスクフォース1を立て直すことがコストの面でもいいんじゃないのか？","ENG":"Wouldn't it make more sense fiscally to put the TASKFORCE 1 back in shape instead?","TWN":"重組第1特遣勢力在財政上也有好處吧？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"물론 그렇습니다만, 때로는 손해를 감수해야 할 때도 있는 법이죠.","JPN":"もちろんそうですが、時には損害を甘んじて受ける必要もあります。","ENG":"That may be the case, but sometimes it's worth bearing the extra cost.","TWN":"話是這麼說，但有時我們也得承擔一下損失。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"중요한 건 태스크포스 1은 결국 관리국에서 통제하는 무력집단이라는 점입니다.","JPN":"大事なのは、タスクフォース1は結局、管理局が統制する武力集団ということです。","ENG":"What's important is that TASKFORCE 1 is ultimately an armed organization controlled by the Administration.","TWN":"重要的是，第1特遣勢力終究還是由管理局掌控的武裝組織。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"말로는 협력관계라고 하지만 실질적으로는 관리국의 뜻대로 움직일 수밖에 없지요.","JPN":"協力関係とは言いますが、実質的には管理局の思うがままに動かざるをえません。","ENG":"Nominally, we're in a coordinating relationship with the Administration, but in truth, we must do as they say.","TWN":"雖然表面是合作關係，但實際上我們只能按照管理局的意願行動。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"당장 엔터프라이즈의 현대화 개장 사업만 해도 필요한 기술 제공이 계속 미뤄지고 있지 않습니까?","JPN":"例えば、エンタープライズの現代化改装事業においても、必要な技術提供がずっと先送りになってきたのです。","ENG":"They're already stalling the technological transfer we need for the Enterprise's modernization project.","TWN":"即使企業號艦船需要立刻進行現代化改裝，他們不是也一直拖延沒有提供技術支援嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"......현장에서 관리국의 태도를 그다지 유쾌하게 여기지 않는다는 건 나도 잘 알고 있네.","JPN":"……現場で管理局の態度をあまり面白く思ってないことは、私も知っているさ。","ENG":"I'm fully aware of how disgruntled our folks are about the Administration's attitude.","TWN":"……我也知道現在管理局的態度不是很友善。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"하지만 그들은 적이 아니야. 너무 민감하게 받아들일 필요는 없다고 생각하는데......","JPN":"だが、彼らは敵ではない。そんなに過敏になる必要はないと思うが……","ENG":"But they are not the enemy. I don't think there's a need to react so sensitively about it...","TWN":"但他們不是敵人。我覺得沒必要這麼敏感……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"장관님, 언제까지 절 떠보실 생각입니까?","JPN":"長官、いつまで私に探りを入れるつもりですか？","ENG":"Sir, how much longer did you plan to keep testing me?","TWN":"長官，您打算試探我到什麼時候？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};